<script lang="ts">
  const html: string = "<h1>Blockquote</h1>\n\n<p>A blockquote is a block-level quotation rendered as a native <code>&lt;blockquote&gt;</code> element. It optionally carries a source citation URL via the <code>cite</code> attribute and visible attribution text rendered inside a <code>&lt;footer&gt;</code>.</p>\n\n<p>Use it to set off extended quotations from surrounding prose, such as quoted passages from articles, interviews, books, speeches, or testimonials.</p>\n\n<h2>Implementation Notes</h2>\n\n<ul>\n<li>Uses a native <code>&lt;blockquote&gt;</code> element for inherent quotation semantics</li>\n<li><code>cite</code> prop maps to the native <code>cite</code> attribute (a URL identifying the source)</li>\n<li><code>citationText</code> prop renders inside a <code>&lt;footer class=\"blockquote-citation\"&gt;</code> element</li>\n<li><code>label</code> prop is optional and overrides the implicit accessible name via <code>aria-label</code></li>\n<li><code>children</code> provide the quoted content</li>\n<li>No JavaScript behavior; the component is passive</li>\n</ul>\n\n<h2>Props</h2>\n\n<ul>\n<li><code>cite</code>: string (optional) -- URL of the source, rendered as <code>cite</code> attribute</li>\n<li><code>citationText</code>: string (optional) -- visible attribution text in the footer</li>\n<li><code>label</code>: string (optional) -- aria-label override</li>\n<li><code>children</code>: slot -- the quoted content</li>\n<li><code>...restProps</code>: any additional HTML attributes</li>\n</ul>\n\n<h2>Usage</h2>\n\n<p>Basic blockquote with quoted content:</p>\n\n<pre><code class=\"language-html\">&lt;Blockquote&gt;\n  &lt;p&gt;The best way to predict the future is to invent it.&lt;/p&gt;\n&lt;/Blockquote&gt;</code></pre>\n\n<p>Blockquote with citation and source URL:</p>\n\n<pre><code class=\"language-html\">&lt;Blockquote cite=\"https://example.com/source\" citationText=\"— Alan Kay, 1971\"&gt;\n  &lt;p&gt;The best way to predict the future is to invent it.&lt;/p&gt;\n&lt;/Blockquote&gt;</code></pre>\n\n<h2>Keyboard Interactions</h2>\n\n<ul>\n<li>None (passive element)</li>\n</ul>\n\n<h2>ARIA</h2>\n\n<ul>\n<li>Implicit <code>blockquote</code> semantics from the <code>&lt;blockquote&gt;</code> element</li>\n<li><code>aria-label</code> optional override of the accessible name</li>\n<li>The <code>cite</code> attribute references the source URL but is not surfaced to most assistive tech</li>\n</ul>\n\n<h2>When to Use</h2>\n\n<ul>\n<li>Use for extended quotations of one or more sentences, especially ones that warrant visual separation.</li>\n<li>Use when the quote has a known author or source you can attribute.</li>\n<li>Use to highlight customer testimonials and pull quotes within editorial layouts.</li>\n</ul>\n\n<h2>When Not to Use</h2>\n\n<ul>\n<li>Do not use for short inline quotations — use the <code>&lt;q&gt;</code> element instead.</li>\n<li>Do not use as a generic styled container — semantic meaning matters.</li>\n</ul>\n\n<h2>Headless</h2>\n\n<p>Renders a native <code>&lt;blockquote&gt;</code> with optional <code>cite</code> and <code>aria-label</code> attributes, and an optional <code>&lt;footer&gt;</code> containing attribution text. Visual treatment of the quote, indentation, decorative quote marks, and footer styling are entirely the consumer's responsibility.</p>\n\n<h2>Styles</h2>\n\n<p>Consumer CSS targets the <code>blockquote</code> class on the root element and the <code>blockquote-citation</code> class on the footer. Provide indentation, optional decorative quote glyphs, and clear separation between the quote body and the attribution.</p>\n\n<h2>Testing</h2>\n\n<ul>\n<li>Verify the component renders a <code>&lt;blockquote&gt;</code> element with class <code>blockquote</code></li>\n<li>Verify the native <code>cite</code> attribute equals the <code>cite</code> prop when provided</li>\n<li>Verify the <code>&lt;footer class=\"blockquote-citation\"&gt;</code> element renders only when <code>citationText</code> is provided</li>\n<li>Verify <code>aria-label</code> is rendered when <code>label</code> is provided</li>\n<li>Verify children content is rendered inside the blockquote</li>\n</ul>\n\n<h2>Advice</h2>\n\n<ul>\n<li><strong>Designers</strong>: Indent the quote body, use a clear typographic hierarchy between the quote and its attribution, and avoid relying on decorative quotation marks alone for meaning.</li>\n<li><strong>Developers</strong>: Always supply <code>cite</code> (URL) and <code>citationText</code> (visible attribution) when the source is known. Keep visual quotation marks in CSS so screen readers do not announce them twice.</li>\n</ul>\n\n<h2>Related components</h2>\n\n<ul>\n<li><code>citation</code> — a citation acknowledges the relevance of a work of another to the topic of discussion</li>\n<li><code>inset-text</code> — indented text to distinguish it from surrounding content</li>\n</ul>\n\n<h2>References</h2>\n\n<ul>\n<li>MDN <code>&lt;blockquote&gt;</code>: https://developer.mozilla.org/en-US/docs/Web/HTML/Element/blockquote</li>\n<li>HTML Living Standard — The blockquote element: https://html.spec.whatwg.org/multipage/grouping-content.html#the-blockquote-element</li>\n<li>Mozilla Protocol Design System: https://protocol.mozilla.org/</li>\n</ul>";
  // BEGIN auto-generated component example consts
  const demoHtml: string = "<div class=\"blockquote\" aria-label=\"a block-level quotation with optional source citation\">Blockquote</div>";
  const svelteSource: string = "// In your Svelte component:\nimport Blockquote from \"lily-design-system-svelte-headless/components/Blockquote/Blockquote.svelte\";\n\n<Blockquote>\n  <!-- content -->\n</Blockquote>\n";
  // END auto-generated component example consts
</script>

